operations.schema:
input ReorderTiersInput {
    tierIds: [OID!]!
    lastModified: DateTime!
}

operations.reducer:
const currentIds = state.tiers.map(t => t.id);
const inputIds = action.input.tierIds;
if (inputIds.length !== currentIds.length) {
    throw new TierIdsMismatchError("Input tier IDs count does not match existing tiers count");
}
const inputSet = new Set(inputIds);
if (inputSet.size !== inputIds.length) {
    throw new DuplicateTierIdError("Input contains duplicate tier IDs");
}
for (const id of currentIds) {
    if (!inputSet.has(id)) {
        throw new TierIdsMismatchError(`Tier ID ${id} exists but was not included in reorder input`);
    }
}
const tierMap = new Map(state.tiers.map(t => [t.id, t]));
state.tiers = inputIds.map(id => tierMap.get(id));
state.lastModified = action.input.lastModified;

const og = state.optionGroups.find(g => g.id === action.input.id);
if (!og) {
    throw new UpdateOptionGroupNotFoundError(`Option group with ID ${action.input.id} not found`);
}
if (action.input.name) og.name = action.input.name;
if (action.input.description !== undefined) og.description = action.input.description || null;
if (action.input.isAddOn !== undefined && action.input.isAddOn !== null) og.isAddOn = action.input.isAddOn;
if (action.input.defaultSelected !== undefined && action.input.defaultSelected !== null) og.defaultSelected = action.input.defaultSelected;
if (action.input.costType !== undefined) og.costType = action.input.costType || null;
if (action.input.availableBillingCycles) og.availableBillingCycles = action.input.availableBillingCycles;
if (action.input.price !== undefined) og.price = action.input.price || null;
if (action.input.currency !== undefined) og.currency = action.input.currency || null;
state.lastModified = action.input.lastModified;

