operations.schema:
input RecurringPriceOptionInput {
    id: OID!
    billingCycle: BillingCycle!
    amount: Amount_Money!
    currency: Currency!
    discount: DiscountRuleInput
}

input SetupCostInput {
    amount: Amount_Money!
    currency: Currency!
    discount: DiscountRuleInput
}

input SetOptionGroupStandalonePricingInput {
    optionGroupId: OID!
    setupCost: SetupCostInput
    recurringPricing: [RecurringPriceOptionInput!]!
    billingCycleDiscounts: [BillingCycleDiscountInput!]
    lastModified: DateTime!
}

operations.reducer:
const og = state.optionGroups.find(g => g.id === action.input.optionGroupId);
if (!og) {
    throw new SetOptionGroupStandalonePricingNotFoundError(`Option group with ID ${action.input.optionGroupId} not found`);
}
og.pricingMode = "STANDALONE";
og.standalonePricing = {
    setupCost: action.input.setupCost ? {
        amount: action.input.setupCost.amount,
        currency: action.input.setupCost.currency,
        discount: action.input.setupCost.discount ? {
            discountType: action.input.setupCost.discount.discountType,
            discountValue: action.input.setupCost.discount.discountValue,
        } : null,
    } : null,
    recurringPricing: action.input.recurringPricing.map(rp => ({
        id: rp.id,
        billingCycle: rp.billingCycle,
        amount: rp.amount,
        currency: rp.currency,
        discount: rp.discount ? {
            discountType: rp.discount.discountType,
            discountValue: rp.discount.discountValue,
        } : null,
    })),
};
if (action.input.billingCycleDiscounts) {
    og.billingCycleDiscounts = action.input.billingCycleDiscounts.map(d => ({
        billingCycle: d.billingCycle,
        discountRule: {
            discountType: d.discountRule.discountType,
            discountValue: d.discountRule.discountValue,
        },
    }));
}
state.lastModified = action.input.lastModified;

const og = state.optionGroups.find(g => g.id === action.input.optionGroupId);
if (!og) {
    throw new AddOptionGroupTierPricingNotFoundError(`Option group with ID ${action.input.optionGroupId} not found`);
}
og.pricingMode = "TIER_DEPENDENT";
if (!og.tierDependentPricing) {
    og.tierDependentPricing = [];
}
og.tierDependentPricing.push({
    id: action.input.tierPricingId,
    tierId: action.input.tierId,
    setupCost: action.input.setupCost ? {
        amount: action.input.setupCost.amount,
        currency: action.input.setupCost.currency,
        discount: action.input.setupCost.discount ? {
            discountType: action.input.setupCost.discount.discountType,
            discountValue: action.input.setupCost.discount.discountValue,
        } : null,
    } : null,
    setupCostDiscounts: (action.input.setupCostDiscounts || []).map(d => ({
        billingCycle: d.billingCycle,
        discountRule: {
            discountType: d.discountRule.discountType,
            discountValue: d.discountRule.discountValue,
        },
    })),
    recurringPricing: action.input.recurringPricing.map(rp => ({
        id: rp.id,
        billingCycle: rp.billingCycle,
        amount: rp.amount,
        currency: rp.currency,
        discount: rp.discount ? {
            discountType: rp.discount.discountType,
            discountValue: rp.discount.discountValue,
        } : null,
    })),
});
state.lastModified = action.input.lastModified;

const og = state.optionGroups.find(g => g.id === action.input.optionGroupId);
if (!og) {
    throw new UpdateOptionGroupTierPricingNotFoundError(`Option group with ID ${action.input.optionGroupId} not found`);
}
const tp = og.tierDependentPricing?.find(t => t.tierId === action.input.tierId);
if (tp) {
    if (action.input.setupCost !== undefined) {
        tp.setupCost = action.input.setupCost ? {
            amount: action.input.setupCost.amount,
            currency: action.input.setupCost.currency,
            discount: action.input.setupCost.discount ? {
                discountType: action.input.setupCost.discount.discountType,
                discountValue: action.input.setupCost.discount.discountValue,
            } : null,
        } : null;
    }
    if (action.input.setupCostDiscounts !== undefined && action.input.setupCostDiscounts !== null) {
        tp.setupCostDiscounts = action.input.setupCostDiscounts.map(d => ({
            billingCycle: d.billingCycle,
            discountRule: {
                discountType: d.discountRule.discountType,
                discountValue: d.discountRule.discountValue,
            },
        }));
    }
    if (action.input.recurringPricing) {
        tp.recurringPricing = action.input.recurringPricing.map(rp => ({
            id: rp.id,
            billingCycle: rp.billingCycle,
            amount: rp.amount,
            currency: rp.currency,
            discount: rp.discount ? {
                discountType: rp.discount.discountType,
                discountValue: rp.discount.discountValue,
            } : null,
        }));
    }
}
state.lastModified = action.input.lastModified;

